package by.sorface.passport.web.security.configimport by.sorface.passport.web.config.options.CookiePropertiesimport by.sorface.passport.web.config.options.EndpointOptionsimport by.sorface.passport.web.security.config.formlogin.JsonUsernamePasswordAuthenticationFilterimport by.sorface.passport.web.security.constants.WhitelistUrlsimport by.sorface.passport.web.security.csrf.CsrfCookieFilterimport by.sorface.passport.web.security.extensions.jsonLoginimport by.sorface.passport.web.security.handlers.RedirectSessionOAuth2Handlerimport by.sorface.passport.web.security.oauth2.provider.service.database.OAuth2UserDatabaseStrategyimport org.springframework.context.annotation.Beanimport org.springframework.context.annotation.Configurationimport org.springframework.http.HttpMethodimport org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilderimport org.springframework.security.config.annotation.authentication.configuration.EnableGlobalAuthenticationimport org.springframework.security.config.annotation.method.configuration.EnableMethodSecurityimport org.springframework.security.config.annotation.web.builders.HttpSecurityimport org.springframework.security.config.annotation.web.configuration.EnableWebSecurityimport org.springframework.security.config.annotation.web.configurers.*import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoderimport org.springframework.security.crypto.password.PasswordEncoderimport org.springframework.security.web.SecurityFilterChainimport org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilterimport org.springframework.security.web.authentication.www.BasicAuthenticationFilterimport org.springframework.security.web.csrf.CookieCsrfTokenRepositoryimport org.springframework.security.web.csrf.CsrfAuthenticationStrategyimport org.springframework.security.web.csrf.CsrfTokenRequestHandlerimport org.springframework.security.web.savedrequest.HttpSessionRequestCacheimport org.springframework.security.web.util.matcher.AntPathRequestMatcher@EnableWebSecurity@EnableMethodSecurity@EnableGlobalAuthentication@Configuration(proxyBeanMethods = false)class SecurityConfig(    private val oAuth2UserDatabaseStrategy: OAuth2UserDatabaseStrategy) {    @Bean    @Throws(Exception::class)    fun defaultSecurityFilterChain(        httpSecurity: HttpSecurity,        redirectSessionOAuth2Handler: RedirectSessionOAuth2Handler,        authenticationFailureHandler: LoginFailureHandler,        exceptionAuthenticationEntryPoint: ExceptionAuthenticationEntryPoint?,        cookieCsrfTokenRepository: CookieCsrfTokenRepository,        csrfTokenRequestHandler: CsrfTokenRequestHandler,        cookieProperties: CookieProperties,        endpointOptions: EndpointOptions    ): SecurityFilterChain {        httpSecurity.getSharedObject(AuthenticationManagerBuilder::class.java)        return httpSecurity            .oauth2Login { oauth2LoginSpec ->                oauth2LoginSpec.userInfoEndpoint { userInfoEndpointSpec -> userInfoEndpointSpec.userService(oAuth2UserDatabaseStrategy) }                oauth2LoginSpec.loginPage(endpointOptions.uriPageSignIn)                oauth2LoginSpec.successHandler(redirectSessionOAuth2Handler)                oauth2LoginSpec.failureHandler(authenticationFailureHandler)            }            .requestCache { httpSecurityRequestCacheConfigurer: RequestCacheConfigurer<HttpSecurity?> ->                val httpSessionRequestCache = HttpSessionRequestCache()                httpSessionRequestCache.setRequestMatcher(AntPathRequestMatcher("/oauth2/**"))                httpSecurityRequestCacheConfigurer.requestCache(httpSessionRequestCache)            }            .csrf { csrfSpec ->                val csrfAuthenticationStrategy = CsrfAuthenticationStrategy(cookieCsrfTokenRepository)                csrfSpec                    .ignoringRequestMatchers(                        AntPathRequestMatcher.antMatcher(HttpMethod.GET),                        AntPathRequestMatcher.antMatcher(HttpMethod.POST, endpointOptions.uriApiLogin)                    )                    .csrfTokenRepository(cookieCsrfTokenRepository)                    .csrfTokenRequestHandler(csrfTokenRequestHandler)                    .sessionAuthenticationStrategy(csrfAuthenticationStrategy)            }            .addFilterAfter(CsrfCookieFilter(), BasicAuthenticationFilter::class.java)            .addFilterAt(JsonUsernamePasswordAuthenticationFilter(), UsernamePasswordAuthenticationFilter::class.java)            .authorizeHttpRequests { authorizeHttpRequestsSpec ->                authorizeHttpRequestsSpec                    .requestMatchers(*WhitelistUrls.WHITE_LIST.patterns.toTypedArray()).permitAll()                    .requestMatchers(*WhitelistUrls.SIGN_UP.patterns.toTypedArray()).anonymous()                    .requestMatchers(HttpMethod.OPTIONS, *WhitelistUrls.toArray(WhitelistUrls.OPTION_REQUEST)).permitAll()                    .requestMatchers(HttpMethod.GET, *WhitelistUrls.toArray(WhitelistUrls.CSRF)).permitAll()                    .requestMatchers(HttpMethod.GET, *WhitelistUrls.toArray(WhitelistUrls.API_ACCOUNT)).permitAll()                    .requestMatchers(*WhitelistUrls.toArray()).permitAll()                    .anyRequest()                    .authenticated()            }            .logout { logoutSpec ->                logoutSpec.disable()            }            .jsonLogin { jsonLoginSpec ->                jsonLoginSpec.loginPage(endpointOptions.uriPageSignIn)                jsonLoginSpec.loginProcessingUrl(endpointOptions.uriApiLogin)                jsonLoginSpec.successHandler(redirectSessionOAuth2Handler)                jsonLoginSpec.failureHandler(authenticationFailureHandler)            }            .exceptionHandling { exceptionHandlingSpec ->                exceptionHandlingSpec.authenticationEntryPoint(exceptionAuthenticationEntryPoint)            }            .build()    }    @Bean    fun passwordEncoder(): PasswordEncoder = BCryptPasswordEncoder(10)}